#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <utility> // For std::pair

// Forward declaration of the user's solution function
void solve(std::istream& in, std::ostream& out);

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        {"5", "Enter a positive integer N: The sum of even numbers is: 6\n"},
        {"10", "Enter a positive integer N: The sum of even numbers is: 30\n"},
        {"abc\n5", "Enter a positive integer N: Invalid input. Please enter an integer: The sum of even numbers is: 6\n"},
        {"0\n2", "Enter a positive integer N: N must be a positive integer. Please enter a positive integer N: The sum of even numbers is: 2\n"},
        {"-5\n4", "Enter a positive integer N: N must be a positive integer. Please enter a positive integer N: The sum of even numbers is: 6\n"},
        {"1\n12", "Enter a positive integer N: N must be a positive integer. Please enter a positive integer N: The sum of even numbers is: 42\n"}
    };

    bool all_passed = true;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::stringstream ss_in(test_cases[i].first);
        std::stringstream ss_out;

        solve(ss_in, ss_out);

        if (ss_out.str() == test_cases[i].second) {
            // std::cout << "Test Case " << i + 1 << " Passed." << std::endl;
        } else {
            std::cerr << "Test Case " << i + 1 << " Failed." << std::endl;
            std::cerr << "Input: \"" << test_cases[i].first << "\"" << std::endl;
            std::cerr << "Expected: \"" << test_cases[i].second << "\"" << std::endl;
            std::cerr << "Got: \"" << ss_out.str() << "\"" << std::endl;
            all_passed = false;
        }
    }

    if (all_passed) {
        return 0;
    } else {
        return 1;
    }
}
